using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainingService(ILogger<ModelTrainingService> logger) : IHostedService
{
    public const string ModelPath = "Data/model.zip";

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.33, seed: 42);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        // Cross-validate on full dataset for more stable metrics with small data
        var cvResults = mlContext.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 3, labelColumnName: "Label");
        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        logger.LogInformation("=== 3-Fold Cross-Validation ===");
        logger.LogInformation("  Avg Macro Accuracy: {AvgMacro:F4}", avgMacro);
        logger.LogInformation("  Avg Micro Accuracy: {AvgMicro:F4}", avgMicro);

        // Retrain on full dataset for production model
        var productionModel = pipeline.Fit(data);
        var savePath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(productionModel, data.Schema, savePath);
        logger.LogInformation("Model saved to {ModelPath}", savePath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

