using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainer
{
    public const string ModelPath = "Data/model.zip";

    public static void TrainAndSave(ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate on full dataset — best metric for small datasets
        logger.LogInformation("Training ticket classification model...");
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 3, labelColumnName: "Label", seed: 42);

        logger.LogInformation("=== 3-Fold Cross-Validation ===");
        foreach (var (fold, r) in cvResults.Select((r, i) => (i + 1, r)))
        {
            logger.LogInformation("  Fold {Fold}: MacroAccuracy={Macro:F4}  MicroAccuracy={Micro:F4}  LogLoss={LogLoss:F4}",
                fold, r.Metrics.MacroAccuracy, r.Metrics.MicroAccuracy, r.Metrics.LogLoss);
        }
        logger.LogInformation("  Average:  MacroAccuracy={Macro:F4}  MicroAccuracy={Micro:F4}",
            cvResults.Average(r => r.Metrics.MacroAccuracy),
            cvResults.Average(r => r.Metrics.MicroAccuracy));

        // Train production model on full dataset
        var model = pipeline.Fit(data);
        var savePath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(model, data.Schema, savePath);
        logger.LogInformation("Model saved to {Path}", savePath);
    }
}

